"use client";

interface DeviceCardProps {
  id: string;
  name: string;
  state: boolean;
  type: 'light' | 'door' | 'aux';
  onToggle: (id: string, currentState: boolean) => void;
}

export default function DeviceCard({ id, name, state, type, onToggle }: DeviceCardProps) {
  
  const getIcon = () => {
    switch (type) {
      case 'light':
        return (
          <div className="w-12 h-12 rounded-full bg-gradient-to-br from-yellow-400/20 to-orange-500/20 flex items-center justify-center mb-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 text-yellow-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9.663 17h4.674M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
            </svg>
          </div>
        );
      case 'door':
        return (
          <div className="w-12 h-12 rounded-full bg-gradient-to-br from-blue-400/20 to-cyan-400/20 flex items-center justify-center mb-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 text-cyan-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
            </svg>
          </div>
        );
      case 'aux':
        return (
          <div className="w-12 h-12 rounded-full bg-gradient-to-br from-purple-400/20 to-pink-400/20 flex items-center justify-center mb-2">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 text-pink-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9.663 17h4.674M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
            </svg>
          </div>
        );
    }
  };

  const getStateText = () => {
    if (type === 'door') return state ? "MỞ" : "ĐÓNG";
    return state ? "BẬT" : "TẮT";
  };

  const getTextColor = () => {
    if (!state) return "text-gray-400";
    if (type === 'light') return "text-yellow-300";
    if (type === 'door') return "text-green-300";
    if (type === 'aux') return "text-pink-300";
  };

  return (
    <div className="device-card p-4 flex flex-col items-center text-center">
      {getIcon()}
      <h3 className="font-bold text-sm text-white">{name}</h3>
      <div className="flex items-center gap-2 mt-1">
        <span className={`text-xs font-mono ${getTextColor()}`}>{getStateText()}</span>
        <button 
          onClick={() => onToggle(id, state)}
          className="text-[10px] text-white bg-white/10 px-2 py-0.5 rounded-full hover:bg-cyan-500/30 transition"
        >
          {type === 'door' ? 'Mở/Đóng' : 'Bật/Tắt'}
        </button>
      </div>
    </div>
  );
}
