"use client";

import { useEffect, useState, useRef } from "react";
import io, { Socket } from "socket.io-client";
import Visualizer from "@/components/Visualizer";
import DeviceCard from "@/components/DeviceCard";
import VoiceControl from "@/components/VoiceControl";
// Assuming you have NextAuth session, we'd normally get devices from DB
// For this demo, we'll manage local state mapped to DB devices eventually

type LogEntry = { id: number; time: string; message: string; type: 'system' | 'error' | 'command' };

export default function Dashboard() {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [history, setHistory] = useState<LogEntry[]>([]);
  const [feedbackText, setFeedbackText] = useState("🎙️ Nhấn micro và nói lệnh (bật/tắt đèn...)");
  
  // Dummy device states matching HTML
  const [devices, setDevices] = useState({
    light: false,
    door: false,
    auxLight: false
  });

  const nextLogId = useRef(1);

  const addLog = (message: string, type: 'system' | 'error' | 'command' = 'command') => {
    const time = new Date().toLocaleTimeString([], {hour:'2-digit', minute:'2-digit', second:'2-digit'});
    setHistory(prev => [{ id: nextLogId.current++, time, message, type }, ...prev].slice(0, 12));
  };

  useEffect(() => {
    // Connect to Node.js backend
    const socketUrl = process.env.NEXT_PUBLIC_SOCKET_URL || "http://localhost:3000";
    const newSocket = io(socketUrl);
    setSocket(newSocket);

    newSocket.on("connect", () => {
      setIsConnected(true);
      addLog("🔌 Kết nối server thành công", "system");
    });

    newSocket.on("disconnect", () => {
      setIsConnected(false);
      addLog("⚠️ Mất kết nối điều khiển", "error");
    });

    return () => {
      newSocket.close();
    };
  }, []);

  const speak = (text: string) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return;
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'vi-VN';
    utterance.rate = 0.9;
    window.speechSynthesis.cancel();
    window.speechSynthesis.speak(utterance);
  };

  const sendDeviceCommand = (deviceId: string, action: string) => {
    if (socket) {
      // Payload matching the requirements
      socket.emit('send_command', { device_id: deviceId, action });
    }
  };

  const toggleDevice = (id: string, currentState: boolean) => {
    if (id === 'light') {
      const newState = !currentState;
      setDevices(prev => ({ ...prev, light: newState }));
      sendDeviceCommand('ESP32_MAC_ADDRESS', newState ? 'L1_ON' : 'L1_OFF');
      addLog(`💡 Đèn chính ${newState ? 'bật' : 'tắt'}`);
      speak(newState ? "Đèn chính đã bật" : "Đèn chính đã tắt");
    } else if (id === 'door') {
      const newState = !currentState;
      setDevices(prev => ({ ...prev, door: newState }));
      // Example commands
      sendDeviceCommand('ESP32_MAC_ADDRESS', newState ? 'DOOR_OPEN' : 'DOOR_CLOSE');
      addLog(`🚪 Cửa ${newState ? 'mở' : 'đóng'}`);
      speak(newState ? "Cửa đã mở" : "Cửa đã đóng");
    } else if (id === 'auxLight') {
      const newState = !currentState;
      setDevices(prev => ({ ...prev, auxLight: newState }));
      sendDeviceCommand('ESP32_MAC_ADDRESS', newState ? 'L2_ON' : 'L2_OFF');
      addLog(`💡 Đèn phụ ${newState ? 'bật' : 'tắt'}`);
      speak(newState ? "Đèn phụ đã sáng" : "Đèn phụ đã tắt");
    }
  };

  const handleVoiceCommand = (transcript: string) => {
    const cmd = transcript.toLowerCase().trim();
    addLog(`🎤 "${transcript}"`, "command");
    let response = "";

    if (cmd.includes("bật đèn") || cmd.includes("mở đèn") && !cmd.includes("phụ")) {
      if (!devices.light) toggleDevice('light', false);
      else response = "Đèn chính đã bật sẵn rồi";
    } else if (cmd.includes("tắt đèn") && !cmd.includes("phụ")) {
      if (devices.light) toggleDevice('light', true);
      else response = "Đèn chính đã tắt";
    } else if (cmd.includes("mở cửa") || cmd.includes("bật cửa")) {
      if (!devices.door) toggleDevice('door', false);
      else response = "Cửa đã mở sẵn";
    } else if (cmd.includes("đóng cửa") || cmd.includes("tắt cửa")) {
      if (devices.door) toggleDevice('door', true);
      else response = "Cửa đã đóng";
    } else if (cmd.includes("bật đèn phụ") || cmd.includes("mở đèn phụ")) {
      if (!devices.auxLight) toggleDevice('auxLight', false);
      else response = "Đèn phụ đã bật";
    } else if (cmd.includes("tắt đèn phụ")) {
      if (devices.auxLight) toggleDevice('auxLight', true);
      else response = "Đèn phụ đã tắt";
    } else {
      response = "Lệnh không hợp lệ. Hãy thử: bật đèn, tắt đèn, mở cửa...";
      addLog(`⚠️ Không nhận dạng: "${transcript}"`, "error");
    }

    if (response) {
      setFeedbackText(`🤖 ${response}`);
      speak(response);
    } else {
      setFeedbackText(`✅ Đã thực thi: "${transcript}"`);
    }

    setTimeout(() => {
      setFeedbackText("🎙️ Nhấn micro và nói lệnh (bật/tắt đèn...)");
    }, 3000);
  };

  return (
    <div className="min-h-screen text-white relative flex flex-col p-4 md:p-6" style={{ background: 'radial-gradient(circle at 20% 30%, #0a0a1a, #010105)'}}>
      {/* Background Noise Effect */}
      <div className="noise" />

      <div className="w-full max-w-5xl mx-auto relative z-10">
        {/* Header */}
        <div className="flex justify-end items-center mb-6 px-2">
          <div className="bg-black/30 backdrop-blur rounded-full px-4 py-2 border border-white/10 flex items-center gap-3">
             <div className="flex items-center gap-2">
                <span className={`status-led ${isConnected ? 'bg-green-400 text-green-400' : 'bg-red-500 text-red-500'}`}></span>
                <span className="text-xs font-mono">{isConnected ? "ONLINE" : "OFFLINE"}</span>
             </div>
             <div className="w-px h-4 bg-white/20"></div>
             <div className="flex items-center gap-2">
                <span className={`status-led ${feedbackText.includes("Đang nghe") ? 'bg-green-400 animate-pulse text-green-400' : 'bg-green-400 text-green-400'}`}></span>
                <span className="text-xs font-mono">{feedbackText.includes("Đang nghe") ? "LISTENING" : "STANDBY"}</span>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main Controls - 2 Columns */}
          <div className="lg:col-span-2 space-y-6">
             <Visualizer isListening={feedbackText.includes("Đang nghe")} />

             <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <DeviceCard id="light" name="Đèn chính" state={devices.light} type="light" onToggle={toggleDevice} />
                <DeviceCard id="door" name="Cửa thông minh" state={devices.door} type="door" onToggle={toggleDevice} />
                <DeviceCard id="auxLight" name="Đèn phụ" state={devices.auxLight} type="aux" onToggle={toggleDevice} />
             </div>

             <VoiceControl onCommand={handleVoiceCommand} statusText={feedbackText} />
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
             {/* History */}
             <div className="glass-panel p-5 flex flex-col h-64">
                <div className="flex justify-between items-center border-b border-white/10 pb-2">
                   <h3 className="font-bold text-sm flex items-center gap-2"><span className="text-cyan-400">⌨️</span> LỆNH GẦN ĐÂY</h3>
                   <button onClick={() => setHistory([])} className="text-[10px] text-gray-400 hover:text-white">Xóa</button>
                </div>
                <div className="flex-1 overflow-y-auto mt-3 space-y-2 text-xs font-mono pr-1 history-scroll">
                   {history.length === 0 ? (
                     <div className="text-gray-500 italic">Chưa có lệnh nào</div>
                   ) : (
                     history.map(log => (
                       <div key={log.id} className={`border-l-2 pl-2 py-1 ${log.type === 'command' ? 'border-cyan-400 text-cyan-300' : log.type === 'error' ? 'border-red-500 text-red-400' : 'border-gray-500 text-gray-300'}`}>
                         <span className="text-gray-500 text-[9px] mr-1">{log.time}</span>
                         <span>{log.message}</span>
                       </div>
                     ))
                   )}
                </div>
             </div>

             {/* AI Tips */}
             <div className="glass-panel p-5">
                 <div className="flex items-center gap-2 mb-3">
                     <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
                     <span className="text-xs font-bold tracking-wider">TRỢ LÝ THÔNG MINH</span>
                 </div>
                 <div className="text-sm leading-relaxed text-gray-300">
                     💡 Gợi ý: "bật đèn", "tắt đèn", "mở cửa", "đóng cửa", "bật đèn phụ", "tắt đèn phụ"
                 </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
}
